if game.PlaceId ~= 123949707464677 then return end
if not game:IsLoaded() then game.Loaded:Wait() end

local player = game:GetService("Players").LocalPlayer
local startBtn = player:WaitForChild("PlayerGui"):WaitForChild("HUD"):WaitForChild("Start")

task.spawn(function()
    repeat task.wait(0.5) until startBtn.Visible == true
    
    local success = false
    if getconnections then
        for _, v in pairs(getconnections(startBtn.MouseButton1Click)) do
            v:Fire()
            success = true
        end
    end
    
    if not success and firesignal then
        firesignal(startBtn.MouseButton1Click)
    end
end)
